import { useCallback, useState } from 'react';

import Stack from '@mui/material/Stack';
import Tab from '@mui/material/Tab';
import Tabs from '@mui/material/Tabs';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useSelectOptions from 'features/shared/useSelectOptions';

function TabPanel({ value, index, children }) {
  if (value !== index) return null;
  return <div>{children}</div>;
}

export default function AcquisitionsPage() {
  const [tab, setTab] = useState(0);
  const ownerLabelBuilder = useCallback((owner) => `${owner.parcel_code} - ${owner.full_name} (${owner.rut})`, []);
  const ownerOptions = useSelectOptions('/maps/parcel-options/', ownerLabelBuilder, { include_inactive: 'true' });

  return (
    <Stack sx={{ gap: 2 }}>
      <Tabs value={tab} onChange={(_, value) => setTab(value)}>
        <Tab label="Controles Remotos" />
        <Tab label="Tarjetas RFID" />
        <Tab label="Logos Vehiculares" />
      </Tabs>

      <TabPanel value={tab} index={0}>
        <CrudResourceModule
          title="Controles Remotos"
          path="/acquisitions/remote-controls/"
          columns={[
            { key: 'serial_number', label: 'Serie' },
            { key: 'owner_display', label: 'Propietario' },
            { key: 'model', label: 'Modelo' },
            { key: 'status', label: 'Estado' },
            { key: 'issued_at', label: 'Fecha entrega' }
          ]}
          fields={() => [
            { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: ownerOptions, required: true },
            { name: 'serial_number', label: 'Serie', required: true },
            { name: 'model', label: 'Modelo' },
            {
              name: 'status',
              label: 'Estado',
              type: 'select',
              options: [
                { value: 'active', label: 'Activo' },
                { value: 'inactive', label: 'Inactivo' },
                { value: 'lost', label: 'Perdido' }
              ],
              required: true
            },
            { name: 'issued_at', label: 'Fecha entrega', type: 'date' }
          ]}
          searchPlaceholder="Buscar por serie, modelo, propietario o parcela..."
        />
      </TabPanel>

      <TabPanel value={tab} index={1}>
        <CrudResourceModule
          title="Tarjetas RFID"
          path="/acquisitions/rfid-cards/"
          columns={[
            { key: 'uid', label: 'UID' },
            { key: 'owner_display', label: 'Propietario' },
            { key: 'color', label: 'Color/Tipo' },
            { key: 'status', label: 'Estado' },
            { key: 'issued_at', label: 'Fecha entrega' }
          ]}
          fields={() => [
            { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: ownerOptions, required: true },
            { name: 'uid', label: 'UID', required: true },
            { name: 'color', label: 'Color o tipo' },
            {
              name: 'status',
              label: 'Estado',
              type: 'select',
              options: [
                { value: 'active', label: 'Activa' },
                { value: 'inactive', label: 'Inactiva' },
                { value: 'lost', label: 'Perdida' }
              ],
              required: true
            },
            { name: 'issued_at', label: 'Fecha entrega', type: 'date' }
          ]}
          searchPlaceholder="Buscar por UID, tipo, propietario o parcela..."
        />
      </TabPanel>

      <TabPanel value={tab} index={2}>
        <CrudResourceModule
          title="Logos Vehiculares"
          path="/acquisitions/vehicle-logos/"
          columns={[
            { key: 'plate', label: 'Patente' },
            { key: 'logo_code', label: 'Codigo logo' },
            { key: 'owner_display', label: 'Propietario' },
            { key: 'status', label: 'Estado' },
            { key: 'issued_at', label: 'Fecha entrega' }
          ]}
          fields={() => [
            { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: ownerOptions, required: true },
            { name: 'plate', label: 'Patente', required: true },
            { name: 'logo_code', label: 'Codigo logo', required: true },
            {
              name: 'status',
              label: 'Estado',
              type: 'select',
              options: [
                { value: 'active', label: 'Activo' },
                { value: 'inactive', label: 'Inactivo' }
              ],
              required: true
            },
            { name: 'issued_at', label: 'Fecha entrega', type: 'date' }
          ]}
          searchPlaceholder="Buscar por patente, codigo, propietario o parcela..."
        />
      </TabPanel>
    </Stack>
  );
}

